<template>
  <div class="carbon-input-page">
    <!-- 导航栏组件 -->
    <NavBar :nickname="user.nickname" class="nav-bar-glass" />
    
    <!-- 页面头部 -->
    <div class="page-header">
      <div class="header-content">
        <h2 class="header-title">碳足迹数据录入</h2>
        <p class="header-desc">记录每一次低碳行为，为地球减负。</p>
      </div>
    </div>

    <!-- 表单区域 -->
    <div class="form-card-container">
      <el-card class="form-card" shadow="never">
        <el-form
          :model="form"
          label-width="90px"
          ref="formRef"
          :rules="formRules"
          class="carbon-form"
        >
          <!-- 基础信息 -->
          <div class="form-section">
            <div class="section-header">
              <span class="section-number">01</span>
              <h4 class="section-title">行为基础信息</h4>
            </div>
            
            <div class="form-row">
              <el-form-item label="行为类型" prop="type" id="behavior-type-item" class="form-item">
                <el-select 
                  v-model="form.type" 
                  placeholder="请选择行为类型" 
                  class="custom-select"
                  @change.native="handleTypeChange"
                  clearable>
                  <el-option 
                    v-for="type in Object.keys(typeDetailMap)"
                    :key="type" 
                    :label="type" 
                    :value="type"
                  ></el-option>
                </el-select>
              </el-form-item>

              <el-form-item label="行为详情" prop="detail" class="form-item">
                <el-select 
                  v-model="form.detail" 
                  placeholder="请先选择行为类型"
                  class="custom-select"
                  @change="handleDetailChange"
                  :disabled="!form.type"
                  clearable
                >
                  <el-option 
                    v-for="item in detailOptions" 
                    :key="item.value" 
                    :label="item.label" 
                    :value="item.value"
                  ></el-option>
                </el-select>
              </el-form-item>
            </div>

            <div class="form-row single">
              <el-form-item label="数量单位" class="form-item">
                <el-input 
                  v-model="unitText" 
                  class="custom-input unit-input"
                  disabled
                  placeholder="自动匹配单位">
                </el-input>
              </el-form-item>
            </div>
          </div>

          <!-- 数量与时间 -->
          <div class="form-section">
            <div class="section-header">
              <span class="section-number">02</span>
              <h4 class="section-title">数量与时间</h4>
            </div>
            
            <div class="form-row">
              <el-form-item label="行为数量" prop="amount" class="form-item">
                <el-input
                  v-model.number="form.amount"
                  type="number"
                  placeholder="请输入数值"
                  min="0"
                  step="0.1"
                  class="custom-input">
                </el-input>
              </el-form-item>

              <el-form-item label="记录日期" prop="recordTime" class="form-item">
                <el-date-picker
                  v-model="form.recordTime"
                  type="date"
                  placeholder="选择日期"
                  value-format="yyyy-MM-dd"
                  class="custom-date"
                  :default-value="new Date()"
                  prefix-icon="el-icon-date"
                ></el-date-picker>
              </el-form-item>
            </div>
          </div>

          <!-- 按钮区域 -->
          <div class="form-actions">
            <el-button type="primary" @click="submitForm" class="action-btn submit-btn">
              <i class="el-icon-check"></i> 提交记录
            </el-button>
            <el-button @click="resetForm" class="action-btn reset-btn">
              <i class="el-icon-refresh-left"></i> 重置
            </el-button>
            <el-button @click="$router.push('/carbonAnalysis')" class="action-btn back-btn">
              返回分析
            </el-button>
          </div>
        </el-form>
      </el-card>
    </div>
    <EcoMascot speechText="记录每一次低碳行为，让减碳更有迹可循～" />
  </div>
</template>

<script>
import EcoMascot from '../components/EcoMascot.vue'
import NavBar from '../components/NavBar.vue'

export default {
  name: 'DataInputPage',
  components: { 
    EcoMascot,
    NavBar
  },
  data() {
    return {
      user: JSON.parse(localStorage.getItem('user')) || {},
      form: {
        userId: 0,
        type: '',
        detail: '',
        amount: '',
        recordTime: new Date().toISOString().split('T')[0]
      },
      formRules: {
        type: [{ required: true, message: '请选择行为类型', trigger: 'change' }],
        detail: [{ required: true, message: '请选择行为详情', trigger: 'change' }],
        amount: [
          { required: true, message: '请输入数量', trigger: 'blur' },
          { type: 'number', min: 0, message: '数量不能为负数', trigger: 'blur' }
        ],
        recordTime: [{ required: true, message: '请选择记录日期', trigger: 'change' }]
      },
      typeDetailMap: {
        "交通出行": [
          { label: "私家车燃油", value: "私家车燃油", unit: "公里" },
          { label: "摩托车", value: "摩托车", unit: "公里" },
          { label: "地铁", value: "地铁", unit: "公里" },
          { label: "公交", value: "公交", unit: "公里" },
          { label: "出租车/网约车", value: "出租车/网约车", unit: "公里" },
          { label: "火车", value: "火车", unit: "公里" },
          { label: "飞机经济舱", value: "飞机经济舱", unit: "公里" },
          { label: "步行", value: "步行", unit: "公里" },
          { label: "自行车", value: "自行车", unit: "公里" },
          { label: "电动车", value: "电动车", unit: "公里" }
        ],
        "家庭能源消耗": [
          { label: "电力消耗", value: "电力消耗", unit: "度" },
          { label: "燃气消耗", value: "燃气消耗", unit: "立方米" },
          { label: "取暖", value: "取暖", unit: "小时" },
          { label: "制冷", value: "制冷", unit: "小时" },
          { label: "水资源消耗", value: "水资源消耗", unit: "吨" }
        ],
        "饮食消费": [
          { label: "牛肉", value: "牛肉", unit: "公斤" },
          { label: "猪肉", value: "猪肉", unit: "公斤" },
          { label: "鸡肉", value: "鸡肉", unit: "公斤" },
          { label: "蔬菜", value: "蔬菜", unit: "公斤" },
          { label: "乳制品", value: "乳制品", unit: "公斤" },
          { label: "谷物", value: "谷物", unit: "公斤" },
          { label: "外卖包装", value: "外卖包装", unit: "次" },
          { label: "厨余垃圾", value: "厨余垃圾", unit: "公斤" }
        ],
        "购物消费": [
          { label: "棉质服装", value: "棉质服装", unit: "件" },
          { label: "化纤服装", value: "化纤服装", unit: "件" },
          { label: "羊毛服装", value: "羊毛服装", unit: "件" },
          { label: "电子产品", value: "电子产品", unit: "件" },
          { label: "塑料制品", value: "塑料制品", unit: "件" },
          { label: "包装材料", value: "包装材料", unit: "件" },
          { label: "快递包装", value: "快递包装", unit: "件" }
        ],
        "垃圾处理": [
          { label: "填埋", value: "填埋", unit: "公斤" },
          { label: "焚烧", value: "焚烧", unit: "公斤" },
          { label: "回收利用", value: "回收利用", unit: "公斤" },
          { label: "有害垃圾", value: "有害垃圾", unit: "公斤" },
          { label: "电子垃圾", value: "电子垃圾", unit: "公斤" }
        ]
      },
      detailOptions: [],
      unitText: ""
    }
  },
  watch: {
    'form.type'(newVal) {
      if (newVal) {
        this.detailOptions = this.typeDetailMap[newVal] || [];
        this.form.detail = "";
        this.unitText = "";
      } else {
        this.detailOptions = [];
        this.form.detail = "";
        this.unitText = "";
      }
    },
    'form.detail'(val) {
      if (!val) return
      const currentTypeDetails = this.typeDetailMap[this.form.type] || []
      const detailItem = currentTypeDetails.find(item => item.value === val)
      this.unitText = detailItem ? detailItem.unit : ""
    }
  },
  mounted() {
    this.checkLoginStatus()
  },
  methods: {
    checkLoginStatus() {
      const userStr = localStorage.getItem('user')
      if (!userStr) {
        this.$message.warning('请先登录后再录入碳足迹数据！')
        this.$router.push('/login')
        return
      }
      const user = JSON.parse(userStr)
      if (!user.id) {
        this.$message.warning('登录信息失效，请重新登录！')
        this.$router.push('/login')
        return
      }
      this.form.userId = user.id
      this.user = user
    },
    handleTypeChange(val) {
      console.log('选择的行为类型：', val);
      console.log('对应的详情数据：', this.typeDetailMap[val]);
      
      this.detailOptions = this.typeDetailMap[val] || [];
      this.form.detail = "";
      this.unitText = "";
    },
    handleDetailChange(val) {
      const currentTypeDetails = this.typeDetailMap[this.form.type] || []
      const detailItem = currentTypeDetails.find(item => item.value === val)
      this.unitText = detailItem ? detailItem.unit : ""
    },
    async submitForm() {
      try {
        await this.$refs.formRef.validate()
        const res = await this.$http.post('/carbon/add', this.form)
        this.$message.success(res.msg || '碳足迹记录提交成功！即将为你生成专属减碳建议~')
        const userRes = await this.$http.get('/user/info', {
          params: { userId: this.form.userId }
        })
        if (userRes.code === 200) {
          localStorage.setItem('user', JSON.stringify(userRes.data))
          this.user = userRes.data
        }
        this.$root.$emit('refreshSuggestion')
        setTimeout(() => {
          this.$router.push('/CarbonAnalysis')
        }, 1500)
      } catch (error) {
        console.error('提交失败：', error)
        this.$message.error('提交失败，请检查信息或重试！')
      }
    },
    resetForm() {
      this.$refs.formRef.resetFields()
      this.form = {
        userId: this.form.userId,
        type: '',
        detail: '',
        amount: '',
        recordTime: new Date().toISOString().split('T')[0]
      }
      this.detailOptions = []
      this.unitText = ""
    }
  }
}
</script>

<style scoped>
.carbon-input-page {
  --primary-color: #10b981;
  --primary-hover: #059669;
  --primary-light: #d1fae5;
  --text-main: #1f2937;
  --text-sub: #1f2022;
  --border-color: #e5e7eb;
  --bg-input: #f9fafb;
  --shadow-card: 0 10px 30px -5px rgba(0, 0, 0, 0.1);
  --radius-lg: 16px;
  --radius-md: 8px;
}

.carbon-input-page {
  position: fixed;
  top: 0;
  left: 0;
  width: 100vw;
  height: 100vh;
  overflow: hidden;
  display: flex;
  flex-direction: column;
  justify-content: center;
  font-family: 'Inter', -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
  background-image: url('~@/assets/datainput.jpg');
  background-size: cover;
  background-position: center;
  background-attachment: fixed;
  padding: 10px 20px;
  box-sizing: border-box;
  color: var(--text-main);
}

.page-header {
  text-align: center;
  margin-bottom: 15px;
  animation: fadeInDown 0.5s ease-out;
}

.header-content {
  display: inline-flex;
  flex-direction: column;
  align-items: center;
}

.header-title {
  font-size: 24px;
  font-weight: 700;
  color: var(--text-main);
  margin: 0 0 6px 0;
  letter-spacing: -0.5px;
}

.header-desc {
  font-size: 13px;
  color: var(--text-sub);
  margin: 0;
}

.form-card-container {
  max-width: 800px;
  margin: 0 auto;
  width: 100%;
  animation: fadeInUp 0.5s ease-out 0.1s backwards;
  max-height: calc(100vh - 40px);
  overflow-y: auto;
  padding-right: 5px;
}

::v-deep .form-card-container::-webkit-scrollbar {
  width: 4px;
}
::v-deep .form-card-container::-webkit-scrollbar-thumb {
  background-color: var(--primary-light);
  border-radius: 2px;
}
::v-deep .form-card-container::-webkit-scrollbar-track {
  background-color: transparent;
}

.form-card {
  border: none;
  border-radius: var(--radius-lg);
  background: rgba(255, 255, 255, 0.85) !important;
  backdrop-filter: blur(8px);
  -webkit-backdrop-filter: blur(8px);
  box-shadow: var(--shadow-card);
  overflow: hidden;
}

.carbon-form {
  padding: 20px 25px;
}

.form-section {
  margin-bottom: 20px;
  position: relative;
}

.form-section:last-of-type {
  margin-bottom: 15px;
}

.section-header {
  display: flex;
  align-items: center;
  margin-bottom: 15px;
  padding-bottom: 8px;
  border-bottom: 1px solid var(--border-color);
}

.section-number {
  font-size: 12px;
  font-weight: 700;
  color: var(--primary-color);
  background: var(--primary-light);
  padding: 2px 8px;
  border-radius: 4px;
  margin-right: 10px;
}

.section-title {
  font-size: 15px;
  font-weight: 600;
  color: var(--text-main);
  margin: 0;
}

.form-row {
  display: flex;
  gap: 12px;
  margin-bottom: 15px;
}

.form-row.single {
  max-width: 50%;
}

.form-item {
  flex: 1;
  margin-bottom: 0 !important;
}

::v-deep .el-form-item__label {
  font-size: 13px;
  font-weight: 600;
  color: var(--text-main);
  line-height: 36px;
  padding-right: 4px !important;
}

::v-deep #behavior-type-item {
  overflow: visible !important;
}
::v-deep #behavior-type-item .el-select {
  transform: translateX(-1px) !important;
  width: calc(100% + 6px) !important;
  position: relative !important;
  z-index: 2 !important;
}
::v-deep #behavior-type-item .el-select .el-input__inner {
  width: 100% !important;
  box-sizing: border-box !important;
}

::v-deep .custom-input .el-input__inner,
::v-deep .custom-select .el-input__inner {
  height: 36px;
  border: 1px solid var(--border-color);
  border-radius: var(--radius-md);
  background-color: var(--bg-input);
  font-size: 13px;
  color: var(--text-main);
  transition: all 0.3s ease;
  padding: 0 12px;
}

::v-deep .custom-input .el-input__inner:hover,
::v-deep .custom-select .el-input__inner:hover {
  border-color: var(--primary-color);
  background-color: #fff;
}

::v-deep .custom-input .el-input__inner:focus,
::v-deep .custom-select .el-input__inner:focus {
  border-color: var(--primary-color);
  box-shadow: 0 0 0 2px rgba(16, 185, 129, 0.1);
  background-color: #fff;
}

::v-deep .unit-input .el-input__inner {
  background-color: #f3f4f6;
  color: var(--text-sub);
  cursor: not-allowed;
  border-color: transparent;
}

::v-deep .custom-date {
  width: 100%;
}
::v-deep .custom-date .el-input__inner {
  height: 36px;
  border: 1px solid var(--border-color);
  border-radius: var(--radius-md);
  background-color: var(--bg-input);
  padding-left: 36px !important;
  padding-right: 12px;
}

::v-deep .custom-date .el-input__prefix {
  left: 8px;
  z-index: 1;
}

::v-deep .el-input-group__prepend,
::v-deep .el-input-group__append {
  background-color: #fff;
  border-color: var(--border-color);
  color: var(--text-sub);
  border-radius: 0 var(--radius-md) var(--radius-md) 0;
  line-height: 34px; 
  padding: 0 10px;
  font-size: 13px;
}

.form-actions {
  display: flex;
  justify-content: center;
  gap: 12px;
  margin-top: 20px;
  padding-top: 15px;
  border-top: 1px dashed var(--border-color);
}

.action-btn {
  height: 36px;
  padding: 0 20px;
  border-radius: var(--radius-md);
  font-size: 13px;
  font-weight: 600;
  transition: all 0.3s;
  border: none;
  min-width: 100px;
}

.submit-btn {
  background: linear-gradient(135deg, var(--primary-color), var(--primary-hover));
  box-shadow: 0 2px 8px rgba(16, 185, 129, 0.25);
}

.submit-btn:hover {
  transform: translateY(-1px);
  box-shadow: 0 4px 12px rgba(16, 185, 129, 0.3);
}

.reset-btn {
  background-color: #fff;
  border: 1px solid var(--border-color);
  color: var(--text-sub);
}

.reset-btn:hover {
  border-color: var(--text-sub);
  color: var(--text-main);
  background-color: #f9fafb;
}

.back-btn {
  background: transparent;
  color: var(--text-sub);
  border: none;
}

.back-btn:hover {
  color: var(--primary-color);
  background: rgba(16, 185, 129, 0.05);
}

@keyframes fadeInDown {
  from { opacity: 0; transform: translateY(-10px); }
  to { opacity: 1; transform: translateY(0); }
}

@keyframes fadeInUp {
  from { opacity: 0; transform: translateY(10px); }
  to { opacity: 1; transform: translateY(0); }
}

@media (max-width: 768px) {
  .carbon-form {
    padding: 15px 15px;
  }
  
  .form-row {
    flex-direction: column;
    gap: 12px;
  }

  .form-row.single {
    max-width: 100%;
  }

  ::v-deep #behavior-type-item .el-select {
    transform: translateX(0) !important;
    width: 100% !important;
  }

  .header-title {
    font-size: 20px;
  }

  .form-actions {
    flex-direction: column;
    gap: 8px;
  }

  .action-btn {
    width: 100%;
  }
}
</style>